namespace UniversityCourseCatalog.Models;

public class Department
{
    public int Id { get; set; }
    public string Name { get; set; } = string.Empty;
    public string Code { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
}

public class Instructor
{
    public int Id { get; set; }
    public string Name { get; set; } = string.Empty;
    public string Title { get; set; } = string.Empty;
    public string Bio { get; set; } = string.Empty;
    public string Email { get; set; } = string.Empty;
}

public class Course
{
    public int Id { get; set; }
    public string Code { get; set; } = string.Empty;
    public string Title { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int Credits { get; set; }
    public string Schedule { get; set; } = string.Empty;
    public int DepartmentId { get; set; }
    public Department Department { get; set; } = null!;
    public int InstructorId { get; set; }
    public Instructor Instructor { get; set; } = null!;
    public bool IsFeatured { get; set; }
}

public class EnrollmentRequest
{
    public string StudentName { get; set; } = string.Empty;
    public string StudentId { get; set; } = string.Empty;
    public int CourseId { get; set; }
}

using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CatalogService
{
    private readonly List<Department> _departments;
    private readonly List<Instructor> _instructors;
    private readonly List<Course> _courses;
    private readonly List<EnrollmentRequest> _enrollmentRequests = new();

    public CatalogService()
    {
        _departments = new List<Department>
        {
            new() { Id = 1, Name = "Computer Science", Code = "CS", Description = "Study of computation, algorithms, and information systems." },
            new() { Id = 2, Name = "Mathematics", Code = "MATH", Description = "Study of numbers, structures, and patterns." },
            new() { Id = 3, Name = "Physics", Code = "PHYS", Description = "Study of matter, energy, and the fundamental forces of nature." },
            new() { Id = 4, Name = "English", Code = "ENG", Description = "Study of literature, writing, and language." },
            new() { Id = 5, Name = "History", Code = "HIST", Description = "Study of past events and civilizations." }
        };

        _instructors = new List<Instructor>
        {
            new() { Id = 1, Name = "Dr. Alice Chen", Title = "Professor of Computer Science", Bio = "Dr. Chen specializes in artificial intelligence and machine learning. She has published over 50 papers and holds three patents in natural language processing.", Email = "achen@university.edu" },
            new() { Id = 2, Name = "Dr. Robert Martinez", Title = "Associate Professor of Mathematics", Bio = "Dr. Martinez researches algebraic topology and has received the National Science Foundation CAREER award. He is known for his engaging teaching style.", Email = "rmartinez@university.edu" },
            new() { Id = 3, Name = "Dr. Sarah Johnson", Title = "Professor of Physics", Bio = "Dr. Johnson is a leading researcher in quantum mechanics and has collaborated with CERN. She brings real-world research experience into the classroom.", Email = "sjohnson@university.edu" },
            new() { Id = 4, Name = "Dr. James Wilson", Title = "Associate Professor of English", Bio = "Dr. Wilson specializes in American literature and creative writing. He has authored two novels and numerous short stories.", Email = "jwilson@university.edu" },
            new() { Id = 5, Name = "Dr. Maria Garcia", Title = "Professor of History", Bio = "Dr. Garcia is an expert in modern European history and has conducted extensive archival research across multiple countries.", Email = "mgarcia@university.edu" },
            new() { Id = 6, Name = "Dr. David Park", Title = "Assistant Professor of Computer Science", Bio = "Dr. Park focuses on distributed systems and cloud computing. Before academia, he spent 10 years as a software engineer at major tech companies.", Email = "dpark@university.edu" }
        };

        _courses = new List<Course>
        {
            new() { Id = 1, Code = "CS 101", Title = "Introduction to Programming", Description = "Learn the fundamentals of programming using Python. Topics include variables, control flow, functions, and basic data structures. No prior experience required.", Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", DepartmentId = 1, InstructorId = 1, IsFeatured = true },
            new() { Id = 2, Code = "CS 201", Title = "Data Structures and Algorithms", Description = "Study of fundamental data structures (arrays, linked lists, trees, graphs) and algorithm design techniques. Prerequisite: CS 101.", Credits = 4, Schedule = "Tue/Thu 10:30–11:50 AM", DepartmentId = 1, InstructorId = 6, IsFeatured = true },
            new() { Id = 3, Code = "CS 350", Title = "Distributed Systems", Description = "Principles of distributed computing including consensus algorithms, replication, and fault tolerance.", Credits = 3, Schedule = "Mon/Wed 2:00–3:20 PM", DepartmentId = 1, InstructorId = 6, IsFeatured = false },
            new() { Id = 4, Code = "MATH 101", Title = "Calculus I", Description = "Limits, derivatives, and integrals of single-variable functions. Applications to physics and engineering.", Credits = 4, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", DepartmentId = 2, InstructorId = 2, IsFeatured = true },
            new() { Id = 5, Code = "MATH 201", Title = "Linear Algebra", Description = "Vector spaces, linear transformations, matrices, determinants, and eigenvalues.", Credits = 3, Schedule = "Tue/Thu 1:00–2:20 PM", DepartmentId = 2, InstructorId = 2, IsFeatured = false },
            new() { Id = 6, Code = "PHYS 101", Title = "General Physics I", Description = "Mechanics, thermodynamics, and waves. Calculus-based introduction to classical physics.", Credits = 4, Schedule = "Mon/Wed/Fri 11:00–11:50 AM", DepartmentId = 3, InstructorId = 3, IsFeatured = true },
            new() { Id = 7, Code = "PHYS 301", Title = "Quantum Mechanics", Description = "Introduction to quantum theory: wave functions, Schrödinger equation, and quantum measurements.", Credits = 3, Schedule = "Tue/Thu 3:00–4:20 PM", DepartmentId = 3, InstructorId = 3, IsFeatured = false },
            new() { Id = 8, Code = "ENG 101", Title = "Composition and Rhetoric", Description = "Develop college-level writing skills through essays, research papers, and peer review.", Credits = 3, Schedule = "Mon/Wed/Fri 1:00–1:50 PM", DepartmentId = 4, InstructorId = 4, IsFeatured = false },
            new() { Id = 9, Code = "ENG 250", Title = "American Literature", Description = "Survey of major American literary works from the colonial period to the present.", Credits = 3, Schedule = "Tue/Thu 10:30–11:50 AM", DepartmentId = 4, InstructorId = 4, IsFeatured = true },
            new() { Id = 10, Code = "HIST 101", Title = "World History I", Description = "Survey of world civilizations from antiquity through the Renaissance.", Credits = 3, Schedule = "Mon/Wed/Fri 2:00–2:50 PM", DepartmentId = 5, InstructorId = 5, IsFeatured = false },
            new() { Id = 11, Code = "HIST 320", Title = "Modern European History", Description = "Europe from the French Revolution to the present: nationalism, industrialization, and global conflict.", Credits = 3, Schedule = "Tue/Thu 1:00–2:20 PM", DepartmentId = 5, InstructorId = 5, IsFeatured = true }
        };

        // Link navigation properties
        foreach (var course in _courses)
        {
            course.Department = _departments.First(d => d.Id == course.DepartmentId);
            course.Instructor = _instructors.First(i => i.Id == course.InstructorId);
        }
    }

    public List<Department> GetDepartments() => _departments;

    public Department? GetDepartment(int id) => _departments.FirstOrDefault(d => d.Id == id);

    public List<Course> GetCourses(string? searchTerm = null, int? departmentId = null)
    {
        var query = _courses.AsEnumerable();

        if (departmentId.HasValue)
            query = query.Where(c => c.DepartmentId == departmentId.Value);

        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            var term = searchTerm.Trim().ToLowerInvariant();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Code.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Description.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return query.ToList();
    }

    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);

    public List<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();

    public void SubmitEnrollmentRequest(EnrollmentRequest request)
    {
        _enrollmentRequests.Add(request);
    }
}

