            new() { Id = 5, Code = "MATH 201", Title = "Linear Algebra", Description = "Vector spaces, linear transformations, matrices, determinants, and eigenvalues.", Credits = 3, Schedule = "Tue/Thu 1:00–2:20 PM", DepartmentId = 2, InstructorId = 2, IsFeatured = false },
            new() { Id = 6, Code = "PHYS 101", Title = "General Physics I", Description = "Mechanics, thermodynamics, and waves. Calculus-based introduction to classical physics.", Credits = 4, Schedule = "Mon/Wed/Fri 11:00–11:50 AM", DepartmentId = 3, InstructorId = 3, IsFeatured = true },
            new() { Id = 7, Code = "PHYS 301", Title = "Quantum Mechanics", Description = "Introduction to quantum theory: wave functions, Schrödinger equation, and quantum measurements.", Credits = 3, Schedule = "Tue/Thu 3:00–4:20 PM", DepartmentId = 3, InstructorId = 3, IsFeatured = false },
            new() { Id = 8, Code = "ENG 101", Title = "Composition and Rhetoric", Description = "Develop college-level writing skills through essays, research papers, and peer review.", Credits = 3, Schedule = "Mon/Wed/Fri 1:00–1:50 PM", DepartmentId = 4, InstructorId = 4, IsFeatured = false },
            new() { Id = 9, Code = "ENG 250", Title = "American Literature", Description = "Survey of major American literary works from the colonial period to the present.", Credits = 3, Schedule = "Tue/Thu 10:30–11:50 AM", DepartmentId = 4, InstructorId = 4, IsFeatured = true },
            new() { Id = 10, Code = "HIST 101", Title = "World History I", Description = "Survey of world civilizations from antiquity through the Renaissance.", Credits = 3, Schedule = "Mon/Wed/Fri 2:00–2:50 PM", DepartmentId = 5, InstructorId = 5, IsFeatured = false },
            new() { Id = 11, Code = "HIST 320", Title = "Modern European History", Description = "Europe from the French Revolution to the present: nationalism, industrialization, and global conflict.", Credits = 3, Schedule = "Tue/Thu 1:00–2:20 PM", DepartmentId = 5, InstructorId = 5, IsFeatured = true }
        };

        // Link navigation properties
        foreach (var course in _courses)
