arguments.file_text:
@page "/"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CatalogService CatalogService

<PageTitle>University Course Catalog</PageTitle>

<div class="container">
    <div class="hero">
        <h1>University Course Catalog</h1>
        <p class="lead">Explore our departments and courses for the upcoming semester.</p>
        <a href="/courses" class="btn btn-primary btn-lg">Browse All Courses</a>
    </div>

    <section class="mt-5">
        <h2>Featured Courses</h2>
        <div class="row mt-3">
            @foreach (var course in _featuredCourses)
            {
                <div class="col-md-4 mb-4">
                    <div class="card h-100">
                        <div class="card-body">
                            <span class="badge bg-secondary mb-2">@course.Department.Name</span>
                            <h5 class="card-title">@course.Code — @course.Title</h5>
                            <p class="card-text text-muted">@course.Credits credits · @course.Schedule</p>
                            <a href="/courses/@course.Id" class="btn btn-outline-primary btn-sm">View Details</a>
                        </div>
                    </div>
                </div>
            }
        </div>
    </section>

    <section class="mt-5">
        <h2>Departments</h2>
        <div class="row mt-3">
            @foreach (var dept in _departments)
            {
                <div class="col-md-4 mb-3">
                    <div class="card">
                        <div class="card-body">
                            <h5 class="card-title">@dept.Name</h5>
                            <p class="card-text">@dept.Description</p>
                            <a href="/courses?department=@dept.Id" class="btn btn-outline-secondary btn-sm">View Courses</a>
                        </div>
                    </div>
                </div>
            }
        </div>
    </section>
</div>

@code {
    private List<Course> _featuredCourses = new();
    private List<Department> _departments = new();

    protected override void OnInitialized()
    {
        _featuredCourses = CatalogService.GetFeaturedCourses();
        _departments = CatalogService.GetDepartments();
    }
}

@page "/courses"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@rendermode InteractiveServer
@inject CatalogService CatalogService
@inject NavigationManager Navigation

<PageTitle>Courses — University Course Catalog</PageTitle>

<div class="container">
    <h1>Course Catalog</h1>

    <div class="row mb-4 mt-3">
        <div class="col-md-6">
            <input type="text" class="form-control" placeholder="Search courses..."
                   @bind="_searchTerm" @bind:event="oninput" @bind:after="ApplyFilters" />
        </div>
        <div class="col-md-4">
            <select class="form-select" @bind="_selectedDepartment" @bind:after="ApplyFilters">
                <option value="0">All Departments</option>
                @foreach (var dept in _departments)
                {
                    <option value="@dept.Id">@dept.Name</option>
                }
            </select>
        </div>
    </div>

    @if (_courses.Any())
    {
        <div class="table-responsive">
            <table class="table table-striped table-hover">
                <thead>
                    <tr>
                        <th>Code</th>
                        <th>Title</th>
                        <th>Department</th>
                        <th>Credits</th>
                        <th>Schedule</th>
                        <th></th>
                    </tr>
                </thead>
                <tbody>
                    @foreach (var course in _courses)
                    {
                        <tr>
                            <td>@course.Code</td>
                            <td>@course.Title</td>
                            <td>@course.Department.Name</td>
                            <td>@course.Credits</td>
                            <td>@course.Schedule</td>
                            <td><a href="/courses/@course.Id" class="btn btn-sm btn-outline-primary">Details</a></td>
                        </tr>
                    }
                </tbody>
            </table>
        </div>
        <p class="text-muted">Showing @_courses.Count course(s)</p>
    }
    else
    {
        <div class="alert alert-info">No courses match your search criteria.</div>
    }
</div>

@code {
    private List<Course> _courses = new();
    private List<Department> _departments = new();
    private string _searchTerm = string.Empty;
    private int _selectedDepartment;

    [SupplyParameterFromQuery(Name = "department")]
    public int? DepartmentFilter { get; set; }

    protected override void OnInitialized()
    {
        _departments = CatalogService.GetDepartments();
        if (DepartmentFilter.HasValue)
            _selectedDepartment = DepartmentFilter.Value;
        ApplyFilters();
    }

    private void ApplyFilters()
    {
        int? deptFilter = _selectedDepartment > 0 ? _selectedDepartment : null;
        _courses = CatalogService.GetCourses(_searchTerm, deptFilter);
    }
}

@page "/enroll"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CatalogService CatalogService

<PageTitle>Enrollment Request — University Course Catalog</PageTitle>

<div class="container">
    <h1>Enrollment Request</h1>
    <p>Submit your enrollment request below. You will receive confirmation via your university email.</p>

    @if (_submitted)
    {
        <div class="alert alert-success">
            <h4>Request Submitted!</h4>
            <p>Your enrollment request for <strong>@_selectedCourseTitle</strong> has been submitted successfully.</p>
            <a href="/courses" class="btn btn-outline-primary">Browse More Courses</a>
        </div>
    }
    else
    {
        <div class="row">
            <div class="col-md-6">
                <form method="post" @formname="enrollment" @onsubmit="HandleSubmit">
                    <AntiforgeryToken />

                    <div class="mb-3">
                        <label for="studentName" class="form-label">Full Name</label>
                        <input type="text" class="form-control" id="studentName" name="StudentName"
                               required @bind="_model.StudentName" />
                    </div>

                    <div class="mb-3">
                        <label for="studentId" class="form-label">Student ID</label>
                        <input type="text" class="form-control" id="studentId" name="StudentId"
                               required placeholder="e.g., S12345678" @bind="_model.StudentId" />
                    </div>

                    <div class="mb-3">
                        <label for="courseId" class="form-label">Course</label>
                        <select class="form-select" id="courseId" name="CourseId" required @bind="_model.CourseId">
                            <option value="0" disabled>Select a course...</option>
                            @foreach (var course in _courses)
                            {
                                <option value="@course.Id">@course.Code — @course.Title</option>
                            }
                        </select>
                    </div>

                    <button type="submit" class="btn btn-primary">Submit Request</button>
                    <a href="/courses" class="btn btn-link">Cancel</a>
                </form>
            </div>
        </div>
    }
</div>

@code {
    [SupplyParameterFromQuery(Name = "course")]
    public int? PreselectedCourse { get; set; }

    [SupplyParameterFromForm]
    private EnrollmentRequest _model { get; set; } = new();

    private List<Course> _courses = new();
    private bool _submitted;
    private string _selectedCourseTitle = string.Empty;

    protected override void OnInitialized()
    {
        _courses = CatalogService.GetCourses();
        if (PreselectedCourse.HasValue && _model.CourseId == 0)
            _model.CourseId = PreselectedCourse.Value;
    }

    private void HandleSubmit()
    {
        var course = CatalogService.GetCourse(_model.CourseId);
        _selectedCourseTitle = course is not null ? $"{course.Code} — {course.Title}" : "Unknown";
        CatalogService.SubmitEnrollmentRequest(_model);
        _submitted = true;
    }
}

