            <div class="col-md-6">
                <form method="post" @formname="enrollment" @onsubmit="HandleSubmit">
                    <AntiforgeryToken />

                    <div class="mb-3">
                        <label for="studentName" class="form-label">Full Name</label>
                        <input type="text" class="form-control" id="studentName" name="StudentName"
                               required @bind="_model.StudentName" />
                    </div>

                    <div class="mb-3">
                        <label for="studentId" class="form-label">Student ID</label>
                        <input type="text" class="form-control" id="studentId" name="StudentId"
                               required placeholder="e.g., S12345678" @bind="_model.StudentId" />
                    </div>

                    <div class="mb-3">
                        <label for="courseId" class="form-label">Course</label>
                        <select class="form-select" id="courseId" name="CourseId" required @bind="_model.CourseId">
                            <option value="0" disabled>Select a course...</option>
                            @foreach (var course in _courses)
                            {
                                <option value="@course.Id">@course.Code — @course.Title</option>
                            }
                        </select>
                    </div>

                    <button type="submit" class="btn btn-primary">Submit Request</button>
                    <a href="/courses" class="btn btn-link">Cancel</a>
                </form>
            </div>
        </div>
    }
</div>

@code {
    [SupplyParameterFromQuery(Name = "course")]
    public int? PreselectedCourse { get; set; }

    [SupplyParameterFromForm]
    private EnrollmentRequest _model { get; set; } = new();

    private List<Course> _courses = new();
    private bool _submitted;
    private string _selectedCourseTitle = string.Empty;

    protected override void OnInitialized()
    {
        _courses = CatalogService.GetCourses();
        if (PreselectedCourse.HasValue && _model.CourseId == 0)
            _model.CourseId = PreselectedCourse.Value;
    }

    private void HandleSubmit()
    {
        var course = CatalogService.GetCourse(_model.CourseId);
        _selectedCourseTitle = course is not null ? $"{course.Code} — {course.Title}" : "Unknown";
        CatalogService.SubmitEnrollmentRequest(_model);
        _submitted = true;
    }
}
